var e=JSON.parse(`[{"id":"L6_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"하아, 하아……!","JPN":"はあ、はあ……！","ENG":"*Huff...* *Huff...*","TWN":"哈啊，哈啊……！"},"stage":{"bg":"CITY_JUNGLE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L7_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"어떻게든 도착한 건가?","JPN":"なんとか辿り着いたか。","ENG":"Did I make it?","TWN":"終於到了嗎？"},"stage":{"bg":"CITY_JUNGLE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"역시 오늘은…… 운이 따르는군.","JPN":"やはり今日は……ついているな。","ENG":"I knew it... today's my lucky day.","TWN":"今天果然……很走運。"},"stage":{"bg":"CITY_JUNGLE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_JUNGLE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"끄윽, 상처를 지혈해야겠네. 자네가 가진 파편을 넘겨주겠나?","JPN":"くうっ……腕の止血をしなければ……君の破片を寄こしてくれないか。","ENG":"Errgh...! I should first stop my bleeding. You there, hand me your Fragment.","TWN":"呃，該給傷口止血了。你能把你的碎片給我嗎？"},"stage":{"bg":"CITY_JUNGLE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_MAGIC_WATER"},{"id":"L14_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"……큭. 큭큭!","JPN":"……く……くくくっ……！","ENG":"Hah... Hah hah!","TWN":"……咳，咳咳！"},"stage":{"bg":"CITY_JUNGLE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"자네…… 설마?","JPN":"君は……まさか？","ENG":"Wait... you're?","TWN":"你……難道？"},"stage":{"bg":"CITY_JUNGLE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"……크아아아아아아아아아악!!!","JPN":"……くああああああああっ！！！","ENG":"...AAAAAAARGH!!!","TWN":"……呃啊啊啊啊！"},"stage":{"bg":"CITY_JUNGLE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_BONE_CRACK"},{"id":"L21_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"마침내 단 둘만 남았군, 제임스……!","JPN":"やっと二人きりになれたな、ジェームス……！","ENG":"It's finally just you and me, James...!","TWN":"終於只剩下我們二個人了，詹姆斯……！"},"stage":{"bg":"CITY_JUNGLE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L23_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"끄윽…… 아, 아아, 아아아아!","JPN":"くうっ……あ、ああ、ああぁぁあ！","ENG":"Argh... Ah... Aaah... Aaaaahhh!","TWN":"嗚……啊，啊啊，啊啊啊啊！"},"stage":{"bg":"CITY_JUNGLE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L24_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"학부장이라고 해봤자, 이래선 그저 추악한 늙은이일 뿐이로군.","JPN":"学部長とはいえ、ただの醜い老人にすぎないな。","ENG":"You may have been a dean, but now you're nothing but an ugly old man.","TWN":"拋去院長的頭銜，你也不過是個醜陋的老頭而已。"},"stage":{"bg":"CITY_JUNGLE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"방금 걸로 척추를 손상시켰네.","JPN":"今ので君は脊髄をやられた。","ENG":"I just damaged your spine with that strike.","TWN":"我剛剛廢了你的脊椎。"},"stage":{"bg":"CITY_JUNGLE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"이제부터 자네는 여생을 하반신 불구로 살아가게 될 거야.","JPN":"残りの人生、下半身を動かせないまま生きることになるだろう。","ENG":"Now, you will have to live the rest of your life as a cripple.","TWN":"從今以後，你的餘生都將半身不遂。"},"stage":{"bg":"CITY_JUNGLE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"수발이 없으면, 대소변조차 가리지 못하겠지.","JPN":"人の助けを借りずには用も足せない。","ENG":"Without the help of others, you won't even be able to use the restroom.","TWN":"如果沒有人侍候，甚至會失禁。"},"stage":{"bg":"CITY_JUNGLE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"하아, 하아! 자네는…… 버넷 경의……!","JPN":"はあ、はあ……！　君は……バーネット卿の……！","ENG":"*Huff!* *Huff!* You're... Sir Burnett's...!","TWN":"哈啊，哈啊！你是……伯內特卿的……！"},"stage":{"bg":"CITY_JUNGLE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"틀렸어.","JPN":"違う。","ENG":"You're wrong.","TWN":"錯了。"},"stage":{"bg":"CITY_JUNGLE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"끄으, 으아아아아아! 아아아아악……!","JPN":"くうっ、うああぁぁあああ！　あぁぁああ……っ！","ENG":"Aaahhhh!! AAAAAAAGH...!","TWN":"呃，呃啊啊啊啊啊！啊啊啊啊啊……！"},"stage":{"bg":"CITY_JUNGLE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L34_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"그건 내가 원하는 답이 아니야.","JPN":"それは俺の聞きたい答えではない。","ENG":"That's not the answer I wanted to hear.","TWN":"那不是我想要的答案。"},"stage":{"bg":"CITY_JUNGLE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"여기는 모건. 에이전트 심볼을 통한 단방향 통신입니다.","JPN":"こちらはモーガン。エージェントシンボルからの一方向通信です。","ENG":"This is Morgan. Using the agent symbol for a one-way communication.","TWN":"這裡是摩根，透過特工象徵進行單向通訊"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L39_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"고고학부장의 신병을 확보하였습니다.","JPN":"考古学部長の身柄を確保しました。","ENG":"I've secured the Dean of Archeology.","TWN":"我找到了考古學教授。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"역시 잡았군요.","JPN":"やはり、捕獲しましたね。","ENG":"So he caught him.","TWN":"果然抓住了。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_LAUGH"}}}},{"id":"L43_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"나 참. 그 교수가 속아넘어갈 정도라니.","JPN":"あの教授が騙されるとは。","ENG":"Blimey. Even that Professor got fooled.","TWN":"真是，那個教授竟然都會上當受騙。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_LAUGH"}}}},{"id":"L45_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"모건 할배는 역시 대단하다니깐.","JPN":"やっぱりモーガンのジジイはすごいな。","ENG":"Morgan's exceptional, I tell ya.","TWN":"摩根老頭果然很厲害。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"……또한 성배 탐색의 지원을 요청하기 위해, 이곳 좌표를 송신하겠습니다.","JPN":"……それから聖杯探索の支援要請のため、こちらの座標を送信します。","ENG":"...Also, I'm sending the coordinates to request reinforcements to search for the Holy Grail.","TWN":"……另外，為請求支援聖杯搜尋的工作，將發送此處座標。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"IHXZ…… 3963BT…….","JPN":"IHXZ……3963BT……","ENG":"IHXZ... 3963BT...","TWN":"IHXZ…… 3963BT……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"기관의 전 인원, 지금 즉시 알비온 호를 준비하세요!","JPN":"機関全員、今すぐアルビオン号の準備を！","ENG":"All agents of the Institution! Prepare Albion immediately!","TWN":"機關全體人員，請立即準備阿爾比恩號！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L3_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"우리는 호수의 기사를 쫓겠습니다.","JPN":"私たちは湖の騎士を追います。","ENG":"We chase after the Knight of the Lake.","TWN":"我們將出發追捕湖水騎士。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"자, 그럼 계속 해볼까? 제임스?","JPN":"さあ、続きをやろうじゃないか。ジェームス。","ENG":"Now, shall we continue, James?","TWN":"那，我們繼續吧？詹姆斯？"},"stage":{"bg":"CITY_JUNGLE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"더 궁금한 게 있나? 손톱이 빠지는 고통은 어땠지? 고막이 찢어지는 느낌은?","JPN":"まだ聞きたいことはあるか？　爪を剝がされる苦痛はどうだ？　鼓膜が破れる感覚は？","ENG":"Anything else you're curious to know? What about the pain of getting your fingernails pulled out? Or what about the sensation of your eardrums tearing?","TWN":"還有什麼好奇的嗎？指甲脫落的痛苦怎麼樣？耳膜撕裂的感覺又如何呢？"},"stage":{"bg":"CITY_JUNGLE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"성배는 어디있나? 자네의 배후는 누구야?","JPN":"聖杯はどこにある？　裏には誰がいる？","ENG":"Where is the Holy Grail? And who are you working for?","TWN":"聖杯在哪裡？幕後主使是誰？"},"stage":{"bg":"CITY_JUNGLE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"허윽, 하아, 하아…….","JPN":"かはっ、はあ、はあ……","ENG":"Argh... *Huff... Huff...*","TWN":"咳，哈啊，哈啊……"},"stage":{"bg":"CITY_JUNGLE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"그렇군. 이제야 떠올랐어. 자네는…… <color=#ffd34c>대환류</color>의 생존자였군.","JPN":"そうか。やっと思い出せた。君は……<color=#ffd34c>大還流</color>の生き残りか。","ENG":"I see. Now I remember who you are. You're... a survivor of the <color=#ffd34c>Great Gyre</color>.","TWN":"原來如此，我現在才想起來。你是……<color=#ffd34c>大環流</color>的倖存者。"},"stage":{"bg":"CITY_JUNGLE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"호오, 이제야 머리가 좀 돌아가나?","JPN":"ほお、やっと頭が回ってきたか？","ENG":"Oh? Finally coming back to your senses, I see?","TWN":"喔，你的腦子現在才開始運轉嗎？"},"stage":{"bg":"CITY_JUNGLE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"그래, 관리실패 이전에 관측된 기묘한 재앙 중 하나였지.","JPN":"そうだ。管理失敗以前に観測された、奇妙な災いの一つだった。","ENG":"Yes. It was one of the strangest observed disasters before the Administration Failure.","TWN":"沒錯，那是管理失敗之前觀測到的奇妙災難之一。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"도시 단위의 사람들이 증발해버렸는데, 누구 하나 기억하지 못하는 대규모 실종사건.","JPN":"都市単位の人間が蒸発したのに、誰一人覚えている者がいない大規模な失踪事件。","ENG":"Groups of people that could fill a city vanished into thin air, but no one could remember this large-scale disappearance.","TWN":"整個城市的人都蒸發掉了，卻無一人記得的大規模失蹤事件。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"그 생존자였던 나조차 서류상으로는 죽은 사람으로 처리되었으니까 말이야.","JPN":"その生き残りの俺すら、書類上では故人になっているしな。","ENG":"Even I, the survivor of that disaster, was reported to be dead on paper.","TWN":"就連身為倖存者我，也在文件上被當作死人處理掉了。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"형님께서 날 구하지 않으셨다면, 알코올중독자가 되어 인생을 낭비했겠지.","JPN":"兄貴に救われてなければ、俺は今頃アルコール依存症になって人生を無駄にしていただろう。","ENG":"If Sir Burnett didn't save me, I would've wasted my life being an alcoholic.","TWN":"要不是大哥救了我，我肯定會成為酒精中毒者，一輩子浪費人生。"},"stage":{"bg":"CITY_JUNGLE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"기관에 합류하고 <color=#ffd34c>새로운 이름</color>을 부여받은 뒤.","JPN":"機関に合流し<color=#ffd34c>新しい名前</color>を与えられた時。","ENG":"But after joining the Institution and receiving a <color=#ffd34c>new name</color>,","TWN":"在加入機關並被賦予了<color=#ffd34c>新的名字</color>之後……"},"stage":{"bg":"CITY_JUNGLE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"나는 그 이름에 맹세했네.","JPN":"俺はこの名に誓った。","ENG":"I made a vow to my name.","TWN":"我就對著這個名字發誓。"},"stage":{"bg":"CITY_JUNGLE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"대환류를 일으킨 학회 녀석들을 전부 찾아내서, 모조리 없애버리자고 말이야.","JPN":"大還流を発生させた学会のやつらを全員探し出し、一人残らず消してやろうと。","ENG":"That I will find every single member of the Society responsible for causing the Great Gyre and kill them all.","TWN":"我要把那些製造大環流的學會成員全部找出來，然後一一消滅掉。"},"stage":{"bg":"CITY_JUNGLE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"그 일념이, 지금의 나를 여기까지 이끌었던 유일한 동기이자…….","JPN":"今の俺は、その一念だけでここまで来ている。そしてそれは……","ENG":"That single thought is the sole motivator that has led me this far, and...","TWN":"那個念頭，是讓我走到這一步的唯一動機……"},"stage":{"bg":"CITY_JUNGLE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"지금은 얼굴조차도 떠올릴 수 없는…… 아내와 자식에 대한 마지막 복수일 테니까.","JPN":"今は顔も思い出せない、妻と子どものためにできる最後の復讐でもある。","ENG":"it will also be my last revenge for my son and wife... whose faces I can't even remember now.","TWN":"也是為迄今連臉都想不起來的……妻子和孩子的最後一次復仇。"},"stage":{"bg":"CITY_JUNGLE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_JUNGLE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"그리고 역시나, 그 사건의 배후에는 당신이 있더군.","JPN":"やはり、事件の背後には君がいた。","ENG":"And just as I thought. You were behind it.","TWN":"果然，那件事的背後有你——"},"stage":{"bg":"CITY_JUNGLE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"<color=#ffd34c>제임스 모리어티</color>.","JPN":"<color=#ffd34c>ジェームス・モリアーティ</color>。","ENG":"<color=#ffd34c>James Moriarty</color>.","TWN":"<color=#ffd34c>詹姆斯·莫里蒂</color>。"},"stage":{"bg":"CITY_JUNGLE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"큭…… 크큭……!","JPN":"クッ……ククッ……！","ENG":"Ke... keke...!","TWN":"呵……呵呵……！"},"stage":{"bg":"CITY_JUNGLE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"뭐가 우습지?","JPN":"何がおかしい？","ENG":"What's so funny?","TWN":"有什麼好笑的？"},"stage":{"bg":"CITY_JUNGLE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"그런…… 그런 흔해 빠진 이유로 여기까지 온 건가……?","JPN":"そんな……そんなありきたりな理由でここまで来たというのか……？","ENG":"Is that... stupid reason why you've come all the way here...?","TWN":"就因為……因為那種蹩腳的理由，你才來到了這裡……？"},"stage":{"bg":"CITY_JUNGLE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"자네도 참 재미없는 인생을 살았군.","JPN":"君の人生もつまらないものだ。","ENG":"What a boring life you have.","TWN":"你是不是吃飽太閒。"},"stage":{"bg":"CITY_JUNGLE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"날 그리 도발하지 않는 편이 좋을 거야, 제임스.","JPN":"あまり俺を煽らない方がいいぞ、ジェームス。","ENG":"It is in your best interest to not taunt me, James.","TWN":"你最好不要挑釁我，詹姆斯。"},"stage":{"bg":"CITY_JUNGLE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"내가 실수로 여기서 자네를 죽여버리면 곤란하거든.","JPN":"誤ってここで君を殺してしまったら困るからな。","ENG":"It'll only be troublesome for me if I kill you by mistake.","TWN":"如果我不小心在這裡殺了你，那就難辦了。"},"stage":{"bg":"CITY_JUNGLE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"큭, 크으……. 대환류라, 오래된 이름이로군.","JPN":"くっ、くく……大還流か、久しぶりに聞いたな。","ENG":"Ke ke... The Great Gyre. Haven't heard that name in a long time.","TWN":"呵，呵呵……大環流，是個老名字呢。"},"stage":{"bg":"CITY_JUNGLE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"그래. 그때도 지금처럼 다른 차원의 신적 존재를 증명하려는 시도를 했었어.","JPN":"そうだ……当時も今と同じく、異次元の神的存在を証明しようとしていた。","ENG":"But yes. Just like now, I tried to prove the existence of a godlike being from another dimension.","TWN":"沒錯，當時也像現在一樣，我試圖證明其他次元中也有神的存在。"},"stage":{"bg":"CITY_JUNGLE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"하지만…… 잘 되지 않았지. 왜 그런 줄 아나?","JPN":"だが……上手くいかなかった。なぜだと思う？","ENG":"However... it didn't work out. Do you know why?","TWN":"但是……並不是很順利。你知道為什麼嗎？"},"stage":{"bg":"CITY_JUNGLE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"무지했기 때문이야.","JPN":"無知だったからだよ。","ENG":"It was because I was ignorant.","TWN":"因為無知。"},"stage":{"bg":"CITY_JUNGLE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"당시 우리는 그릇이란 존재를 몰랐거든.","JPN":"当時の我々は、器の存在を知らなかった。","ENG":"At the time, we didn't know vessels existed.","TWN":"當時我們不知道器皿的存在。"},"stage":{"bg":"CITY_JUNGLE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_JUNGLE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"그렇다면…… 최고 품질의 그릇, 성배가 준비된 이번에는 어떨까?","JPN":"だが……最高品質の器、聖杯を用意している今ならどうだ？","ENG":"Then... what do you think will happen since we have the best quality vessel, the Holy Grail, prepared this time?","TWN":"那麼……已準備好最高品質器皿，聖杯的這一次，結果會如何呢？"},"stage":{"bg":"CITY_JUNGLE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"성공할까? 또 실패하고 말까? 궁금하지 않나, 새디어스 모건?","JPN":"今回は成功するだろうか？　それともまた失敗に終わるのか？　気にならないか？　タデウス・モーガン。","ENG":"Will it be successful? Or will it be another failure? Aren't you curious to know, Thaddeus Morgan?","TWN":"會成功？還是失敗？難道你不好奇嗎，薩迪烏斯·摩根？"},"stage":{"bg":"CITY_JUNGLE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"아니, 조사관 헤이스팅스 퍼시…….","JPN":"いや、調査官パーシヴァル・ヘースティングス……","ENG":"Or should I say, Investigator Percival Hastings–","TWN":"不，應該叫你調查官珀西瓦里·哈斯丁……"},"stage":{"bg":"CITY_JUNGLE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"끄아아아아아악!!","JPN":"くあああああああつ！！","ENG":"AAARGH!!","TWN":"啊啊啊啊啊啊！！"},"stage":{"bg":"CITY_JUNGLE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L10_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"이런, 손가락에 힘이 들어가버렸군.","JPN":"おっと、指に力が入ってしまった。","ENG":"Oh, no. Maybe I put in a bit too much force.","TWN":"哎呀，一不小心手指頭就使勁了。"},"stage":{"bg":"CITY_JUNGLE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"엄살부리지 말게. 그럭저럭 움직일 수는 있을 테니까.","JPN":"弱音を吐くな。まだ体は動かせるだろう？","ENG":"Stop being so dramatic. You're still able to move around a little bit.","TWN":"別裝模作樣了，你應該還可以勉強動一動。"},"stage":{"bg":"CITY_JUNGLE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"날 안내하도록 해, 제임스.","JPN":"俺を案内しろ、ジェームス。","ENG":"Lead the way, James.","TWN":"帶我去吧，詹姆斯。"},"stage":{"bg":"CITY_JUNGLE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"바닥을 기어서…… 성배가 있는 곳까지.","JPN":"聖杯のところまで……這いつくばってでも。","ENG":"Crawl, and... take me to where the Holy Grail is.","TWN":"在地上爬著……帶我到聖杯所在的地方吧。"},"stage":{"bg":"CITY_JUNGLE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};